function solve(n, edges, label) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 0;

    // We'll use a bitmask to represent visited nodes (n <= 14)
    const visited = new Array(n).fill(false);

    // Function to perform DFS
    function dfs(node, pathChars) {
        visited[node] = true;
        pathChars.push(label[node]);

        // Check if current path is a palindrome
        if (isPalindrome(pathChars)) {
            maxLen = Math.max(maxLen, pathChars.length);
        }

        // Explore neighbors
        for (const neighbor of adj[node]) {
            if (!visited[neighbor]) {
                dfs(neighbor, [...pathChars]);
            }
        }

        visited[node] = false;
    }

    // Helper to check if array of chars is a palindrome
    function isPalindrome(chars) {
        let left = 0, right = chars.length - 1;
        while (left < right) {
            if (chars[left] !== chars[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }

    // Start DFS from every node
    for (let i = 0; i < n; i++) {
        dfs(i, []);
    }

    return maxLen;
}
